// Client-side Routing
import { BrowserRouter, Routes, Route } from 'react-router-dom';

function App() {
  return (
    <BrowserRouter>
      <Routes>
        <Route path="/" element={<Home />} />
        <Route path="/products" element={<Products />} />
        <Route path="/products/:id" element={<ProductDetail />} />
        <Route path="/cart" element={<Cart />} />
        <Route path="*" element={<NotFound />} />
      </Routes>
    </BrowserRouter>
  );
}

// Navegação sem reload. URLs limpas. Transições suaves.

// State Management
const initialState = { user: null, cart: [], products: [] };
const reducer = (state = initialState, action) => {
  switch (action.type) {
    case 'SET_USER': return { ...state, user: action.payload };
    case 'ADD_TO_CART': return { ...state, cart: [...state.cart, action.payload] };
    default: return state;
  }
};
const store = createStore(reducer);

// Estado centralizado. Mudanças previsíveis. Debugging fácil.

// API Calls
async function fetchProducts() {
  const response = await fetch('/api/products');
  return response.json();
}

async function createOrder(orderData) {
  const response = await fetch('/api/orders', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(orderData)
  });
  return response.json();
}

